import { motion, AnimatePresence } from "framer-motion";
import { Search, ChevronDown, Plus, Pencil, Trash2 } from "lucide-react";

const LinkShow = ({
  links,
  search,
  setSearch,
  sort,
  setSort,
  sortOptions,
  dropdownOpen,
  setDropdownOpen,
  dropdownRef,
  setView,
  handleDelete,
  handleEdit,
}) => {
  return (
    <div className="mt-6 sm:mt-8 space-y-6">

      <AnimatePresence mode="wait">
        <motion.div
          key="home"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.3 }}
          className="space-y-6"
        >

          {/* ================= TOP BAR ================= */}
          <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4 bg-white p-4 sm:p-5 rounded-2xl border border-slate-200 shadow-sm">

            {/* Search */}
            <div className="flex items-center gap-3 bg-slate-100 px-4 py-2.5 rounded-xl w-full lg:w-80 focus-within:ring-2 focus-within:ring-slate-400 transition">
              <Search size={16} className="text-slate-500" />
              <input
                type="text"
                placeholder="Search link..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="bg-transparent outline-none text-xs sm:text-sm md:text-base w-full text-slate-700 placeholder:text-slate-400"
              />
            </div>

            {/* Add Button */}
            <button
              onClick={() => setView("add")}
              className="inline-flex items-center justify-center gap-2 bg-gradient-to-r from-slate-700 to-slate-900 hover:from-slate-800 hover:to-black text-white px-5 py-2.5 rounded-xl text-xs sm:text-sm md:text-base font-medium shadow-md hover:shadow-lg transition-all w-full lg:w-auto"
            >
              <Plus size={16} />
              Add Link
            </button>

          </div>

          {/* ================= TABLE ================= */}
          {links.length > 0 ? (
            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm">

              {/* Table Header Top */}
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 px-4 sm:px-6 py-4 border-b border-slate-200 bg-slate-50">

                <h2 className="text-sm sm:text-base md:text-lg font-semibold text-slate-800">
                  Parent Links List
                </h2>

                {/* Sorting Dropdown */}
                <div className="relative w-full sm:w-auto" ref={dropdownRef}>
                  <button
                    onClick={() => setDropdownOpen(!dropdownOpen)}
                    className="flex items-center justify-between gap-2 w-full sm:w-auto text-xs sm:text-sm md:text-base bg-white border border-slate-300 px-4 py-2 rounded-xl shadow-sm hover:shadow-md transition"
                  >
                    {
                      sortOptions.find(
                        (o) => o.value === sort
                      )?.label
                    }
                    <ChevronDown size={14} />
                  </button>

                  <AnimatePresence>
                    {dropdownOpen && (
                      <motion.div
                        initial={{ opacity: 0, y: -6 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0 }}
                        className="absolute right-0 mt-2 w-full sm:w-44 bg-white border border-slate-200 rounded-xl shadow-xl overflow-hidden z-50"
                      >
                        {sortOptions.map((option) => (
                          <div
                            key={option.value}
                            onClick={() => {
                              setSort(option.value);
                              setDropdownOpen(false);
                            }}
                            className={`px-4 py-2 text-xs sm:text-sm md:text-base hover:bg-slate-100 cursor-pointer ${
                              sort === option.value
                                ? "bg-slate-100 font-semibold"
                                : ""
                            }`}
                          >
                            {option.label}
                          </div>
                        ))}
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>

              </div>

              {/* Table */}
              <div>

                {/* Table Header */}
                <div className="grid grid-cols-4 items-center px-4 sm:px-6 py-3 text-xs sm:text-sm md:text-base font-semibold text-slate-600 border-b border-slate-200">
                  <div>#</div>
                  <div>Name</div>
                  <div>Status</div>
                  <div className="text-right">Actions</div>
                </div>

                {/* Table Body */}
                {links.map((link, index) => (
                  <div
                    key={link._id}
                    className="grid grid-cols-4 items-center px-4 sm:px-6 py-3 text-xs sm:text-sm md:text-base text-slate-700 border-b border-slate-100 hover:bg-slate-50 transition"
                  >
                    <div>{index + 1}</div>

                    {/* Name */}
                    <div className="truncate font-medium">
                      {link.name}
                    </div>

                    {/* Status (Now same style as name column) */}
                    <div
                      className={`font-medium ${
                        link.isActive
                          ? "text-green-600"
                          : "text-red-600"
                      }`}
                    >
                      {link.isActive ? "Active" : "Inactive"}
                    </div>

                    {/* Actions */}
                    <div className="flex justify-end gap-3 sm:gap-4">
                      <Pencil
                        size={16}
                        className="cursor-pointer hover:text-slate-900 transition"
                        onClick={() => handleEdit(link)}
                      />
                      <Trash2
                        size={16}
                        className="text-red-500 cursor-pointer hover:text-red-600 transition"
                        onClick={() => handleDelete(link._id)}
                      />
                    </div>
                  </div>
                ))}

              </div>

            </div>
          ) : (
            <div className="bg-white border border-slate-200 rounded-2xl p-8 text-center text-slate-500 text-sm sm:text-base">
              No parent links found.
            </div>
          )}

        </motion.div>
      </AnimatePresence>
    </div>
  );
};

export default LinkShow;
